# serve.py
import joblib
from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()
model = joblib.load("model/model.joblib")

class Item(BaseModel):
    features: list[float]

@app.post("/predict")
def predict(item: Item):
    pred = model.predict([item.features])[0]
    return {"prediction": float(pred)}
